diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 8be2eeed84ad..ed4fe0230ae5 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -1448,6 +1448,14 @@ Instruction *InstCombinerImpl::foldSelectEqualityTest(SelectInst &Sel) {
              m_c_SpecificICmp(ICmpInst::ICMP_EQ, m_Specific(X), m_Specific(Y))))
     return nullptr;

+  // Avoid folding through an equality icmp marked with "samesign".
+  // A samesign icmp may produce poison when the operands have different
+  // signs, while the original pattern may have masked the poison via
+  // select semantics. Replacing the whole expression with the compare would
+  // make the result more poisonous.
+  if (cast<ICmpInst>(XeqY)->hasSameSign())
+    return nullptr;
+
   return replaceInstUsesWith(Sel, XeqY);
 }

diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 8be2eeed84ad..b32e6cdffa09 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -1448,6 +1448,20 @@ Instruction *InstCombinerImpl::foldSelectEqualityTest(SelectInst &Sel) {
              m_c_SpecificICmp(ICmpInst::ICMP_EQ, m_Specific(X), m_Specific(Y))))
     return nullptr;

+
+  // If the equality compare is marked with "samesign", folding directly to it
+  // may make the result more poisonous than the original pattern, because
+  // a samesign icmp can be poison when operands have differing signs while the
+  // original selects may have masked that poison. In that case, build a plain
+  // equality compare without the samesign flag.
+  if (auto *XeqYCmp = dyn_cast<ICmpInst>(XeqY)) {
+    if (XeqYCmp->hasSameSign()) {
+      Builder.SetInsertPoint(&Sel);
+      Value *NewCmp = Builder.CreateICmpEQ(X, Y);
+      return replaceInstUsesWith(Sel, NewCmp);
+    }
+  }
+
   return replaceInstUsesWith(Sel, XeqY);
 }

